    # Simple structural validation:
    # - Numbers are sequences of digits.
    # - Operators are + - * /
    # - Allow unary + or - at the start, or immediately after '(' or another operator.
    last = 'start'  # one of: start, num, op, lp, rp, op_unary
    i = 0
    n = len(expr)

    while i < n:
